from pyspark.sql.functions import lit


def drop_case_insensitive_duplicates(df):
    seen = set()
    keep = []
    for c in df.columns:
        lc = c.lower()
        if lc not in seen:
            seen.add(lc)
            keep.append(c)
    return df.select(*keep)

def normalize_cols_lower(df):
    for c in df.columns:
        df = df.withColumnRenamed(c, c.lower())
    return df

def add_missing_cols(df, cols):
    for c in cols:
        if c not in df.columns:
            df = df.withColumn(c, lit(None).cast("string"))
    return df.select(*cols)


